const cfg = $('⚙️ Load Config').item.json;
const raw = cfg.A_B_TESTING_ENABLED;
const enabled = raw === true || String(raw).toLowerCase() === 'true';
return [{ json: { A_B_TESTING_ENABLED: enabled, ...cfg } }];

const config = $('⚙️ Load Config').item.json;
const tz = config.CONTENT_DAY_TIMEZONE || config.TIMEZONE || 'UTC';
const today = new Date().toLocaleDateString('en-CA', { timeZone: tz });
const yesterday = new Date(new Date(today).getTime() - 86400000).toISOString().slice(0, 10);
const rows = $input.all().map(i => i.json);
const dateKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'date') || 'date';
const statusKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'status') || 'status';
const urlKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('url') || k === 'WP URL') || 'wp_url';
const valid = rows.filter(r => {
  const d = (r[dateKey] || r.date || '').toString().slice(0, 10);
  const s = (r[statusKey] || r.status || '').toLowerCase();
  return d === yesterday && s !== 'publish_failed';
});
if (valid.length === 0) return [{ json: { noPostYesterday: true } }];
const latest = valid[valid.length - 1];
const wpUrl = (latest[urlKey] || latest.wp_url || '').toString();
const slug = wpUrl.split('/').filter(Boolean).pop() || '';
return [{ json: { ...latest, slug, wpUrl, noPostYesterday: false } }];

// Parse test variants
const raw = $input.first().json.response || '';
const postData = $('Fetch Post Content').item.json;

let testSuite;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  testSuite = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  testSuite = {
    test_suite_id: 'TEST_' + Date.now(),
    title_variants: [],
    parse_error: e.message
  };
}

return [{
  json: {
    post_id: postData.id,
    post_url: postData.link,
    original_title: postData.title?.rendered,
    test_suite: testSuite,
    test_start_date: new Date().toISOString(),
    test_duration_hours: 72,
    test_status: 'ready',
    traffic_split: { A: 33, B: 33, C: 34 }
  }
}];

// Update WordPress post with variant tracking
const testData = $input.first().json;

// Inject A/B test JavaScript into post content
const abTestScript = `
<script>
(function() {
  const testId = '${testData.test_suite.test_suite_id}';
  const variants = {
    title: ${JSON.stringify(testData.test_suite.title_variants.map(v => ({id: v.id, text: v.text})))},
    intro: ${JSON.stringify(testData.test_suite.intro_variants.map(v => ({id: v.id, text: v.text})))},
    cta: ${JSON.stringify(testData.test_suite.cta_variants.map(v => ({id: v.id, text: v.text, color: v.color})))}
  };

  // Simple variant assignment (use cookie or localStorage)
  let userVariant = localStorage.getItem('ab_variant_' + testId);
  if (!userVariant) {
    const rand = Math.random();
    userVariant = rand < 0.33 ? 'A' : rand < 0.67 ? 'B' : 'C';
    localStorage.setItem('ab_variant_' + testId, userVariant);
  }

  // Apply variant
  const titleVar = variants.title.find(v => v.id === userVariant);
  const introVar = variants.intro.find(v => v.id === userVariant);
  const ctaVar = variants.cta.find(v => v.id === userVariant);

  if (titleVar) document.title = titleVar.text;
  if (introVar && document.querySelector('.entry-content p:first-child')) {
    document.querySelector('.entry-content p:first-child').textContent = introVar.text;
  }
  if (ctaVar && document.querySelector('.cta-button')) {
    const btn = document.querySelector('.cta-button');
    btn.textContent = ctaVar.text;
    btn.style.backgroundColor = ctaVar.color;
  }

  // Track impression
  fetch('/wp-json/howtogenie/v1/ab-impression', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({test_id: testId, variant: userVariant, metric: 'impression'})
  });

  // Track engagement
  let engaged = false;
  setTimeout(() => {
    if (!engaged) {
      engaged = true;
      fetch('/wp-json/howtogenie/v1/ab-impression', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({test_id: testId, variant: userVariant, metric: 'engaged'})
      });
    }
  }, 30000);
})();
</script>
`;

return [{
  json: {
    ...testData,
    ab_script: abTestScript,
    tracking_endpoint: '/wp-json/howtogenie/v1/ab-impression',
    ready_to_deploy: true
  }
}];
